import{_ as s,o as a,c as e,aw as n}from"./chunks/framework.Dq2onT5h.js";const t=JSON.parse('{"title":"Fee Systems","description":"","frontmatter":{"head":[["meta",{"name":"og:title","content":"Fee Systems | Evolve"},{"name":"og:description","content":false}]]},"headers":[],"relativePath":"concepts/fee-systems.md","filePath":"concepts/fee-systems.md","lastUpdated":1772446570000}');const o=s({name:"concepts/fee-systems.md"},[["render",function(s,t,o,l,p,c){return a(),e("div",null,[...t[0]||(t[0]=[n('<h1 id="fee-systems" tabindex="-1">Fee Systems <a class="header-anchor" href="#fee-systems" aria-label="Permalink to &quot;Fee Systems&quot;">​</a></h1><p>Evolve chains have two layers of fees: execution fees (paid to process transactions) and DA fees (paid to post data).</p><h2 id="execution-fees" tabindex="-1">Execution Fees <a class="header-anchor" href="#execution-fees" aria-label="Permalink to &quot;Execution Fees&quot;">​</a></h2><h3 id="evm-ev-reth" tabindex="-1">EVM (ev-reth) <a class="header-anchor" href="#evm-ev-reth" aria-label="Permalink to &quot;EVM (ev-reth)&quot;">​</a></h3><p>Uses EIP-1559 fee model:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span>Transaction Fee = (Base Fee + Priority Fee) × Gas Used</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Component</th><th>Destination</th><th>Purpose</th></tr></thead><tbody><tr><td>Base Fee</td><td>Burned (or redirected)</td><td>Congestion pricing</td></tr><tr><td>Priority Fee</td><td>Sequencer</td><td>Incentive for inclusion</td></tr></tbody></table><h4 id="base-fee-redirect" tabindex="-1">Base Fee Redirect <a class="header-anchor" href="#base-fee-redirect" aria-label="Permalink to &quot;Base Fee Redirect&quot;">​</a></h4><p>By default, base fees are burned. ev-reth can redirect them to a treasury:</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#767676;">{</span></span>\n<span class="line"><span style="color:#94EEFF77;">  &quot;</span><span style="color:#94EEFF;">config</span><span style="color:#94EEFF77;">&quot;</span><span style="color:#767676;">:</span><span style="color:#767676;"> {</span></span>\n<span class="line"><span style="color:#94EEFF77;">    &quot;</span><span style="color:#94EEFF;">evolve</span><span style="color:#94EEFF77;">&quot;</span><span style="color:#767676;">:</span><span style="color:#767676;"> {</span></span>\n<span class="line"><span style="color:#94EEFF77;">      &quot;</span><span style="color:#94EEFF;">baseFeeSink</span><span style="color:#94EEFF77;">&quot;</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">0xTREASURY</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#767676;">,</span></span>\n<span class="line"><span style="color:#94EEFF77;">      &quot;</span><span style="color:#94EEFF;">baseFeeRedirectActivationHeight</span><span style="color:#94EEFF77;">&quot;</span><span style="color:#767676;">:</span><span style="color:#FFECB6;"> 0</span></span>\n<span class="line"><span style="color:#767676;">    }</span></span>\n<span class="line"><span style="color:#767676;">  }</span></span>\n<span class="line"><span style="color:#767676;">}</span></span></code></pre></div><p>See <a href="/ev-reth/features/base-fee-redirect">Base Fee Redirect</a> for details.</p><h3 id="cosmos-sdk-ev-abci" tabindex="-1">Cosmos SDK (ev-abci) <a class="header-anchor" href="#cosmos-sdk-ev-abci" aria-label="Permalink to &quot;Cosmos SDK (ev-abci)&quot;">​</a></h3><p>Uses standard Cosmos SDK fee model:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span>Transaction Fee = Gas Price × Gas Used</span></span></code></pre></div><p>Configure minimum gas prices:</p><div class="language-toml"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#A0A0A0;"># app.toml</span></span>\n<span class="line"><span style="color:#DBD7CA;">minimum-gas-prices </span><span style="color:#767676;">=</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">0.025stake</span><span style="color:#BFF3C280;">&quot;</span></span></code></pre></div><p>Fees go to the fee collector module and can be distributed via standard Cosmos mechanisms.</p><h2 id="da-fees" tabindex="-1">DA Fees <a class="header-anchor" href="#da-fees" aria-label="Permalink to &quot;DA Fees&quot;">​</a></h2><p>Both execution environments incur DA fees when blocks are posted to the DA layer.</p><h3 id="cost-factors" tabindex="-1">Cost Factors <a class="header-anchor" href="#cost-factors" aria-label="Permalink to &quot;Cost Factors&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Factor</th><th>Impact</th></tr></thead><tbody><tr><td>Block size</td><td>Linear cost increase</td></tr><tr><td>DA gas price</td><td>Market-driven, varies</td></tr><tr><td>Batching</td><td>Amortizes overhead</td></tr><tr><td>Compression</td><td>Reduces data size</td></tr></tbody></table><h3 id="who-pays" tabindex="-1">Who Pays? <a class="header-anchor" href="#who-pays" aria-label="Permalink to &quot;Who Pays?&quot;">​</a></h3><p>The sequencer pays DA fees from their own funds. They recover costs through:</p><ul><li>Priority fees from users</li><li>Base fee redirect (if configured)</li><li>External subsidy</li></ul><h3 id="optimization-strategies" tabindex="-1">Optimization Strategies <a class="header-anchor" href="#optimization-strategies" aria-label="Permalink to &quot;Optimization Strategies&quot;">​</a></h3><h4 id="lazy-aggregation" tabindex="-1">Lazy Aggregation <a class="header-anchor" href="#lazy-aggregation" aria-label="Permalink to &quot;Lazy Aggregation&quot;">​</a></h4><p>Only produce blocks when there are transactions:</p><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">node</span><span style="color:#767676;">:</span></span>\n<span class="line"><span style="color:#94EEFF;">  lazy-aggregator</span><span style="color:#767676;">:</span><span style="color:#FFECB6;"> true</span></span>\n<span class="line"><span style="color:#94EEFF;">  lazy-block-time</span><span style="color:#767676;">:</span><span style="color:#BFF3C2;"> 1s</span><span style="color:#A0A0A0;">  # Max wait time</span></span></code></pre></div><p>Reduces empty blocks and DA costs.</p><h4 id="batching" tabindex="-1">Batching <a class="header-anchor" href="#batching" aria-label="Permalink to &quot;Batching&quot;">​</a></h4><p>ev-node batches multiple blocks into single DA submissions:</p><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">da</span><span style="color:#767676;">:</span></span>\n<span class="line"><span style="color:#94EEFF;">  batch-size-threshold</span><span style="color:#767676;">:</span><span style="color:#FFECB6;"> 100000</span><span style="color:#A0A0A0;">  # bytes</span></span>\n<span class="line"><span style="color:#94EEFF;">  batch-max-delay</span><span style="color:#767676;">:</span><span style="color:#BFF3C2;"> 5s</span></span></code></pre></div><h4 id="compression" tabindex="-1">Compression <a class="header-anchor" href="#compression" aria-label="Permalink to &quot;Compression&quot;">​</a></h4><p>Enable blob compression:</p><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">da</span><span style="color:#767676;">:</span></span>\n<span class="line"><span style="color:#94EEFF;">  compression</span><span style="color:#767676;">:</span><span style="color:#FFECB6;"> true</span></span></code></pre></div><h2 id="fee-flow-diagram" tabindex="-1">Fee Flow Diagram <a class="header-anchor" href="#fee-flow-diagram" aria-label="Permalink to &quot;Fee Flow Diagram&quot;">​</a></h2><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span>User Transaction</span></span>\n<span class="line"><span>      │</span></span>\n<span class="line"><span>      │ Pays: Gas Price × Gas</span></span>\n<span class="line"><span>      ▼</span></span>\n<span class="line"><span>┌─────────────────┐</span></span>\n<span class="line"><span>│    Sequencer    │</span></span>\n<span class="line"><span>│                 │</span></span>\n<span class="line"><span>│ Receives:       │</span></span>\n<span class="line"><span>│ - Priority fees │</span></span>\n<span class="line"><span>│ - Base fees*    │</span></span>\n<span class="line"><span>└────────┬────────┘</span></span>\n<span class="line"><span>         │</span></span>\n<span class="line"><span>         │ Pays: DA fees</span></span>\n<span class="line"><span>         ▼</span></span>\n<span class="line"><span>┌─────────────────┐</span></span>\n<span class="line"><span>│    DA Layer     │</span></span>\n<span class="line"><span>│   (Celestia)    │</span></span>\n<span class="line"><span>└─────────────────┘</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>* If base fee redirect is enabled</span></span></code></pre></div><h2 id="estimating-costs" tabindex="-1">Estimating Costs <a class="header-anchor" href="#estimating-costs" aria-label="Permalink to &quot;Estimating Costs&quot;">​</a></h2><h3 id="execution-costs" tabindex="-1">Execution Costs <a class="header-anchor" href="#execution-costs" aria-label="Permalink to &quot;Execution Costs&quot;">​</a></h3><p>EVM:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">cast</span><span style="color:#BFF3C2;"> estimate</span><span style="color:#FFECB6;"> --rpc-url</span><span style="color:#BFF3C2;"> http://localhost:8545</span><span style="color:#888888;"> &lt;</span><span style="color:#BFF3C2;">CONTRAC</span><span style="color:#DBD7CA;">T</span><span style="color:#888888;">&gt;</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">transfer(address,uint256)</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#888888;"> &lt;</span><span style="color:#BFF3C2;">T</span><span style="color:#DBD7CA;">O</span><span style="color:#888888;">&gt;</span><span style="color:#888888;"> &lt;</span><span style="color:#BFF3C2;">AMOUN</span><span style="color:#DBD7CA;">T</span><span style="color:#888888;">&gt;</span></span></code></pre></div><p>Cosmos:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">appd</span><span style="color:#BFF3C2;"> tx</span><span style="color:#BFF3C2;"> bank</span><span style="color:#BFF3C2;"> send</span><span style="color:#888888;"> &lt;</span><span style="color:#BFF3C2;">FRO</span><span style="color:#DBD7CA;">M</span><span style="color:#888888;">&gt;</span><span style="color:#888888;"> &lt;</span><span style="color:#BFF3C2;">T</span><span style="color:#DBD7CA;">O</span><span style="color:#888888;">&gt;</span><span style="color:#BFF3C2;"> 1000stake</span><span style="color:#FFECB6;"> --gas</span><span style="color:#BFF3C2;"> auto</span><span style="color:#FFECB6;"> --gas-adjustment</span><span style="color:#FFECB6;"> 1.3</span></span></code></pre></div><h3 id="da-costs" tabindex="-1">DA Costs <a class="header-anchor" href="#da-costs" aria-label="Permalink to &quot;DA Costs&quot;">​</a></h3><p>Depends on:</p><ul><li>DA layer pricing (e.g., Celestia gas price)</li><li>Data size per block</li><li>Submission frequency</li></ul><p>Use the <a href="/guides/tools/celestia-gas-calculator">Celestia Gas Calculator</a> for estimates.</p>',47)])])}]]);export{t as __pageData,o as default};
